-- Adendo 3 PART 1: acervo CET COMPLETO (205 câmeras via folder-probe /Cams/<n>/1.jpg).
-- As 11 nomeadas (037) são puladas por ON CONFLICT(snapshot_url), preservando nome+coord geocodificada.
-- As demais entram genéricas no centro REAL de SP (clustering agrupa; approx_location=true).
-- PART 2: coluna preview_url (pôster do popup).
ALTER TABLE public_cameras ADD COLUMN IF NOT EXISTS preview_url TEXT;

ON CONFLICT (snapshot_url) DO NOTHING;

-- Prévia das câmeras YouTube = thumbnail oficial (imagem real).
UPDATE public_cameras
   SET preview_url = 'https://img.youtube.com/vi/'||substring(video_url from 'embed/([A-Za-z0-9_-]{11})')||'/hqdefault.jpg'
 WHERE stream_type='video' AND video_kind='youtube' AND video_url ~ 'embed/[A-Za-z0-9_-]{11}';
